define i32 @negative_divisior_only(i32 %x, i32 %z) {
entry:
  %sub1 = sub nsw i32 0, %z
  %div2 = sdiv i32 %x, %sub1
  ret i32 %div2
}

define i32 @sdiv_mul_nsw_sub_nsw(i32 %x, i32 %y) {
  %m = mul nsw i32 %y, %x
  %n = sub nsw i32 0, %m
  %d = sdiv i32 %m, %n
  ret i32 %d
}

define i8 @sdiv_sdiv_mul_nsw_exact_exact(i8 %x, i8 %y, i8 %z) {
  %m = mul nsw i8 %x, %y
  %d = sdiv exact i8 %m, %z
  %r = sdiv exact i8 %d, %x
  ret i8 %r
}
